fn power(mut base: i64, mut exp: i64) -> i64 {
    let mut res = 1;
    base %= MOD;
    while exp > 0 {
        if exp % 2 == 1 {
            res = (res * base) % MOD;
        }
        base = (base * base) % MOD;
        exp /= 2;
    }
    res
}

fn mod_inverse(n: i64) -> i64 {
    power(n, MOD - 2)
}

fn solve(n: i64, pos: i64, k: i64) -> i64 {
    if k < 0 || k > n - 1 {
        return 0;
    }

    let n_usize = n as usize;
    let pos_usize = pos as usize;
    let k_usize = k as usize;

    let l = pos_usize; // Number of people to the left (0 to pos-1)
    let r = n_usize - 1 - pos_usize; // Number of people to the right (pos+1 to n-1)

    // 1. Precompute factorials up to N
    let max_val = n_usize;
    let mut fact = vec![1_i64; max_val + 1];
    for i in 1..=max_val {
        fact[i] = (fact[i - 1] * i as i64) % MOD;
